var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"나 참, 뭘 또 귀찮게 이런 걸 준비했대. 한가하면 시내에라도 놀러 갈 것이지.","JPN":"まったく、なんでこんな準備してんだ？\\n暇なら街にでも遊びに行ったらどうだ。","ENG":"Mate, why did you waste your time preparing all this? If you've got nothing else to do, go have some fun downtown.","TWN":"真是的，你怎麼又費心準備這種東西啊。這麼閒的話，就去市中心玩一玩啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"뭐? 종신계약?","JPN":"はあ？　終身契約？","ENG":"What? A lifetime contract?","TWN":"什麼？終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_TOUCH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"............","JPN":"……","ENG":"............","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"크흠, 흠.","JPN":"ご、ごほん。","ENG":"Hmm, Hmm.","TWN":"咳、咳咳！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"하. 왜, 왜 이래, 이거? 가뜩이나 할아범들한테 시달려서 정신없는 사람한테?","JPN":"はぁ。な、何でだ？\\nただでさえジジイたちにこき使われて大変なのに？","ENG":"*Sigh* Why are you doing this to me? Am I not being bullied enough by the gaffers?","TWN":"哈啊，怎、怎麼了，這是怎樣！對一個被老頭們搞得快瘋掉的人說這種事！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"애초에 생각을 해 보라고. 나 같은 양아치를 회사에 둬 봤자 뭐가 좋겠냐. 회사 이미지만 망가진다니까?","JPN":"よく考えてみろ。俺みたいなちんぴらを雇ってもいいことなんてねえぞ。会社のイメージが悪くなるだけだからな。","ENG":"Did you even think about it? Why would you want to keep a no-mark like me? I'd be only good at running down your company's reputation.","TWN":"你重新想想吧。把我這樣的小混混留在公司裡，能有什麼好處？只會破壞公司的形象吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"이쯤 했으면 알아들었지. 간다.","JPN":"ここまで言えばわかるよな。じゃあな。","ENG":"So, you've heard me. I'm leaving now.","TWN":"我都說到這個程度了，你應該明白了吧。我走了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"뭐, 뭔데! 젠장. 그렇게 섭섭한 표정 지으면 내가 무슨 인간 쓰레기 같잖아.","JPN":"な、何だよ！\\nくそ、そんなに寂しそうな顔されると、俺が悪いみたいじゃねえか。","ENG":"Wh-what now?! Drat, stop looking at me like that. You're making me feel like I killed a puppy.","TWN":"真是的，幹嘛啦！該死，你露出這麼寂寞的表情，不就搞得我好像人渣一樣嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_CHANGE","text":{"KOREA":"이리 내놔, 계약서. 까짓 거 찍자고!","JPN":"出せよ、契約書。契約してやるから！","ENG":"Gimme the contract. I'll sign it!","TWN":"契約書給我啦，這樣總行了吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};